                        .where("G", blocks(GTBlocks.CASING_HSSE_STURDY.get()))
                        .where("H", blocks(GTLBlocks.HSSS_REINFORCED_BOROSILICATE_GLASS.get()))
                        .where(" ", Predicates.any())
                        .build()
                }
                ).apply(MultiBlockMachineA.ADVANCED_INTEGRATED_ORE_PROCESSOR)
        }

        GTMachines.ACTIVE_TRANSFORMER.patternFactory = SupplierMemoizer.memoize {
            (
                Function { definition: MultiblockMachineDefinition ->
                    FactoryBlockPattern.start()
                        .aisle("XXX", "XXX", "XXX")
                        .aisle("XXX", "XCX", "XXX")
                        .aisle("XXX", "XSX", "XXX")
                        .where('S', Predicates.controller(blocks(GTMachines.ACTIVE_TRANSFORMER.get())))
                        .where(
                            'X',
                            blocks(GTBlocks.HIGH_POWER_CASING.get())
                                .or(ActiveTransformerMachine.getHatchPredicates())
                        )
                        .where('C', blocks(GTBlocks.SUPERCONDUCTING_COIL.get()))
                        .build()
                }
                ).apply(GTMachines.ACTIVE_TRANSFORMER)
        }
    }
}
